module top_module( multiplicand , b, result);input [7:0]  multiplicand ;
    input [7:0] b;
    output reg [15:0] result;
    integer i; // Declare i as an integer

    always @ ( multiplicand , b)
    begin
        result = 0;
        for (i = 0; i < 8; i = i + 1)
        begin
            if (b[i] == 1)
            begin
                result = result + ( multiplicand  << i);
            end
        end
    end
endmodule
